using UnityEngine;

/// <summary>
/// Tarefa #7 — Pinguim: travagem/curva instantânea, exclusiva em cima de
/// gelo (PlayerMotor2D.IsOnIce). Reduz bruscamente a velocidade horizontal
/// ao premir o botão de Habilidade, dando controlo de curvas que o
/// iceSlideFactor normal (atrito reduzido constante) não permite.
/// </summary>
[RequireComponent(typeof(PlayerMotor2D), typeof(Rigidbody2D))]
public class IceBrakeAbility : MonoBehaviour, IFormAbility, IAbility, IActiveAbility
{
    private bool enabledForForm;
    private AnimalFormData form;
    private PlayerMotor2D motor;
    private Rigidbody2D rb;

    private float cooldownTimer;

    private void Awake()
    {
        motor = GetComponent<PlayerMotor2D>();
        rb = GetComponent<Rigidbody2D>();
    }

    private void Update()
    {
        if (cooldownTimer > 0f) cooldownTimer -= Time.deltaTime;
    }

    public void ConfigureFromForm(AnimalFormData newForm)
    {
        form = newForm;
        enabledForForm = form != null && form.primaryAbility == PrimaryAbility.IceBrake;
        cooldownTimer = 0f;
    }

    /// <summary>Chamado pelo AbilityRouter (botão de Habilidade). Só tem efeito em cima de gelo.</summary>
    public void TryBrake()
    {
        if (!enabledForForm || cooldownTimer > 0f) return;
        if (!motor.IsOnIce || !motor.IsGrounded) return;

        cooldownTimer = 0.15f;

        float strength = form.iceBrakeStrength > 0f ? form.iceBrakeStrength : 6f;
        float newVx = Mathf.MoveTowards(rb.velocity.x, 0f, strength);
        rb.velocity = new Vector2(newVx, rb.velocity.y);

        motor.Anim?.SetTrigger("IceBrake");
    }

    void IAbility.Activate() => TryBrake();
    void IAbility.Release() { }
    public void Cancel(AbilityCancelReason reason) { }
    public float CooldownRemaining => Mathf.Max(0f, cooldownTimer);
    bool IAbility.IsActive => false;
    public float CooldownDuration => 0f;
    public bool CanActivate => enabledForForm && cooldownTimer <= 0f && motor.IsOnIce && motor.IsGrounded;
    public void ResetCooldown() => cooldownTimer = 0f;
}
